from dataclasses import dataclass


@dataclass
class BudgetReallocation:
    from_initiative: str
    to_initiative: str
    amount_gbp: float
    rationale: str
    effective_date: str   # ISO date string

    def summary(self) -> str:
        return (
            f"£{self.amount_gbp:,.0f} from '{self.from_initiative}' "
            f"→ '{self.to_initiative}': {self.rationale}"
        )


# Rebalancing decisions from the session above
reallocations = [
    BudgetReallocation(
        from_initiative="Internal Search Prototype (INI-003)",
        to_initiative="Customer Support Bot scale-up (INI-002)",
        amount_gbp=30_000,
        rationale="INI-003 STOP decision; INI-002 in ACCELERATE quadrant with proven KPI lift",
        effective_date="2026-07-15",
    ),
]

print("Reallocation Register")
for r in reallocations:
    print(f"  {r.effective_date}: {r.summary()}")
